163	func getDRADelta(newAttr, oldAttr *draQuotaAttr) map[string]*api.DRAResource {
164		if newAttr == nil {
165			return nil
166		}
167		delta := make(map[string]*api.DRAResource)
168	
169		// Create union of keys
170		keys := make(map[string]struct{})
171		if newAttr.allocated != nil {
172			for k := range newAttr.allocated {
173				keys[k] = struct{}{}
174			}
175		}
176		if oldAttr != nil && oldAttr.allocated != nil {
177			for k := range oldAttr.allocated {
178				keys[k] = struct{}{}
179			}
180		}
181	
182		for k := range keys {
183			var newRes, oldRes *api.DRAResource
184			if newAttr.allocated != nil {
185				newRes = newAttr.allocated[k]
186			}
187			if oldAttr != nil && oldAttr.allocated != nil {
188				oldRes = oldAttr.allocated[k]
189			}
190	
191			res := &api.DRAResource{Capacity: make(map[string]resource.Quantity)}
192			if newRes != nil {
193				res.Count = newRes.Count
194				for dim, val := range newRes.Capacity {
195					res.Capacity[dim] = val.DeepCopy()
196				}
197			}
198			if oldRes != nil {
199				res.Count -= oldRes.Count
200				for dim, val := range oldRes.Capacity {
201					q := res.Capacity[dim]
202					q.Sub(val)
203					res.Capacity[dim] = q
204				}
205			}
206			delta[k] = res
207		}
208		return delta
209	}
