211	// checkDRAAllocatable checks if a task's DRA requests fit within queue's DRA capability.
212	// consumableCapacityEnabled controls whether the Capacity dimensions are also checked.
213	func checkDRAAllocatable(dra *draQuotaAttr, taskDRA map[string]*api.DRAResource, consumableCapacityEnabled bool) bool {
214		if dra == nil || taskDRA == nil {
215			return true // no DRA quota configured or no DRA requests
216		}
217	
218		for deviceClass, request := range taskDRA {
219			capability, exists := dra.capability[deviceClass]
220			if !exists {
221				// No capability configured for this DeviceClass → no quota limit, allow
222				klog.V(5).Infof("checkDRAAllocatable: No capability for %s, passing through", deviceClass)
223				continue
224			}
225	
226			allocated := dra.allocated[deviceClass]
227			allocatedCount := int64(0)
228			if allocated != nil {
229				allocatedCount = allocated.Count
230			}
231	
232			klog.V(5).Infof("checkDRAAllocatable: deviceClass=%s, allocated=%d, request=%d, capability=%d",
233				deviceClass, allocatedCount, request.Count, capability.Count)
234	
235			if capability.Count > 0 && allocatedCount+request.Count > capability.Count {
236				klog.V(3).Infof("checkDRAAllocatable: count exceeded for %s: allocated=%d, requested=%d, capability=%d",
237					deviceClass, allocatedCount, request.Count, capability.Count)
238				return false
239			}
240	
241			// Check capacity dimensions (only when DRAConsumableCapacity feature is enabled)
242			if consumableCapacityEnabled {
243				for dim, reqQty := range request.Capacity {
244					capQty, ok := capability.Capacity[dim]
245					if !ok {
246						return false // dimension not in capability
247					}
248					var allocQty resource.Quantity
249					if allocated != nil {
250						allocQty = allocated.Capacity[dim]
251					}
252					futureUsed := allocQty.DeepCopy()
253					futureUsed.Add(reqQty)
254					if futureUsed.Cmp(capQty) > 0 {
255						return false
256					}
257				}
258			}
259		}
260		return true
261	}
